#!/usr/bin/env node
/**
 * Bundle size baseline recorder and budget enforcer.
 *
 * Reads .next/BUILD_MANIFEST.json (generated by `next build`) and computes
 * total JS chunk sizes by entry type (pages, app, shared). Compares against
 * `bundle-size-budget.json` if it exists; fails CI when any entry exceeds
 * its budget by more than 10%.
 *
 * Usage:
 *   node scripts/bundle-size-check.mjs            # record + enforce
 *   node scripts/bundle-size-check.mjs --update    # rewrite budget file
 */
import fs from "node:fs";
import path from "node:path";

const ROOT = path.resolve(import.meta.dirname, "..");
const BUILD_DIR = path.join(ROOT, ".next");
const BUDGET_PATH = path.join(ROOT, "bundle-size-budget.json");
const TOLERANCE = 0.10; // 10% over budget before failing

function readBuildManifest() {
  const manifestPath = path.join(BUILD_DIR, "build-manifest.json");
  if (!fs.existsSync(manifestPath)) {
    console.error("No .next/build-manifest.json — run `npm run build` first.");
    process.exit(1);
  }
  return JSON.parse(fs.readFileSync(manifestPath, "utf-8"));
}

function measureChunks() {
  const staticDir = path.join(BUILD_DIR, "static");
  if (!fs.existsSync(staticDir)) {
    console.error("No .next/static/ — build may be incomplete.");
    process.exit(1);
  }

  let totalBytes = 0;
  const entries = {};

  function walk(dir, label) {
    if (!fs.existsSync(dir)) return;
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
      const full = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        walk(full, label);
      } else if (entry.name.endsWith(".js")) {
        const size = fs.statSync(full).size;
        totalBytes += size;
        entries[label] = (entries[label] || 0) + size;
      }
    }
  }

  walk(path.join(staticDir, "chunks"), "chunks");
  walk(path.join(staticDir, "css"), "css");

  for (const sub of fs.readdirSync(staticDir, { withFileTypes: true })) {
    if (sub.isDirectory() && sub.name !== "chunks" && sub.name !== "css" && sub.name !== "media") {
      walk(path.join(staticDir, sub.name), sub.name);
    }
  }

  return { totalBytes, entries };
}

function formatKB(bytes) {
  return `${(bytes / 1024).toFixed(1)} KB`;
}

const doUpdate = process.argv.includes("--update");
const { totalBytes, entries } = measureChunks();

console.log(`\nBundle size snapshot:`);
console.log(`  Total JS: ${formatKB(totalBytes)}`);
for (const [label, bytes] of Object.entries(entries).sort((a, b) => b[1] - a[1])) {
  console.log(`  ${label}: ${formatKB(bytes)}`);
}

if (doUpdate || !fs.existsSync(BUDGET_PATH)) {
  const budget = { totalBytes, entries, recorded: new Date().toISOString() };
  fs.writeFileSync(BUDGET_PATH, JSON.stringify(budget, null, 2) + "\n");
  console.log(`\nBudget ${doUpdate ? "updated" : "created"}: ${BUDGET_PATH}`);
  process.exit(0);
}

const budget = JSON.parse(fs.readFileSync(BUDGET_PATH, "utf-8"));
let failed = false;

if (totalBytes > budget.totalBytes * (1 + TOLERANCE)) {
  console.error(`\nFAIL: Total JS ${formatKB(totalBytes)} exceeds budget ${formatKB(budget.totalBytes)} by >${(TOLERANCE * 100).toFixed(0)}%`);
  failed = true;
} else {
  console.log(`\nTotal JS within budget (${formatKB(totalBytes)} vs ${formatKB(budget.totalBytes)} limit).`);
}

for (const [label, budgetBytes] of Object.entries(budget.entries || {})) {
  const actual = entries[label] || 0;
  if (actual > budgetBytes * (1 + TOLERANCE)) {
    console.error(`FAIL: ${label} ${formatKB(actual)} exceeds budget ${formatKB(budgetBytes)} by >${(TOLERANCE * 100).toFixed(0)}%`);
    failed = true;
  }
}

if (failed) {
  console.error("\nBundle size budget exceeded. Run `node scripts/bundle-size-check.mjs --update` to reset the baseline.");
  process.exit(1);
}

console.log("Bundle size check passed.");
